// Prefer ExecutorService over raw threads
ExecutorService pool = Executors.newFixedThreadPool(4);

// Submit a Runnable (no return value)
pool.submit(() -> System.out.println("task"));

// Submit a Callable (returns a value)
Future<Integer> future = pool.submit(() -> 42);
int result = future.get(); // blocks until done

// Always shut down the pool
pool.shutdown();
pool.awaitTermination(5, TimeUnit.SECONDS);

// Thread states
Thread t = new Thread(() -> {});
System.out.println(t.getState()); // NEW
t.start();
// State transitions: NEW → RUNNABLE → TERMINATED

// synchronized — simple, automatic unlock
public synchronized void increment() {
    count++;
}

// synchronized block (finer grain)
public void transfer(Account from, Account to, int amount) {
    synchronized (from) {
        synchronized (to) {
            from.debit(amount);
            to.credit(amount);
        }
    }
}

// ReentrantLock — more control
private final ReentrantLock lock = new ReentrantLock();

public void doWork() {
    lock.lock();
    try {
        // critical section
    } finally {
        lock.unlock(); // ALWAYS in finally
    }
}

// tryLock — non-blocking attempt
if (lock.tryLock(100, TimeUnit.MILLISECONDS)) {
    try { /* ... */ } finally { lock.unlock(); }
} else {
    // could not acquire — handle gracefully
}

// Visibility problem without volatile
class Flag {
    private boolean stop = false; // JIT may cache in register
    void requestStop() { stop = true; }
    void run() {
        while (!stop) { /* may loop forever — never sees write */ }
    }
}

// Fixed with volatile
class Flag {
    private volatile boolean stop = false; // always reads from memory
    void requestStop() { stop = true; }
    void run() {
        while (!stop) { /* correctly terminates */ }
    }
}

// BROKEN double-checked locking (without volatile)
class Singleton {
    private static Singleton instance;
    public static Singleton get() {
        if (instance == null) {
            synchronized (Singleton.class) {
                if (instance == null)
                    instance = new Singleton(); // partially constructed object can escape!
            }
        }
        return instance;
    }
}
// Fix: declare instance as volatile

// Basic async chain
CompletableFuture<String> future = CompletableFuture
    .supplyAsync(() -> fetchUserId())          // runs on ForkJoinPool
    .thenApply(id -> "User-" + id)             // transform result
    .thenApply(String::toUpperCase);

String result = future.join();  // block and get (or use get())

// Error handling
CompletableFuture<String> safe = CompletableFuture
    .supplyAsync(() -> riskyCall())
    .exceptionally(ex -> "fallback");

// Wait for multiple futures
CompletableFuture<String> f1 = fetchName();
CompletableFuture<Integer> f2 = fetchAge();
CompletableFuture.allOf(f1, f2).join();
System.out.println(f1.join() + " age " + f2.join());

// Custom executor (avoid blocking ForkJoinPool with I/O)
Executor ioPool = Executors.newCachedThreadPool();
CompletableFuture.supplyAsync(() -> readFromDB(), ioPool);

// thenApply: synchronous transform
CompletableFuture<String> cf1 = getIdAsync()
    .thenApply(id -> "prefix-" + id);  // String → String

// thenCompose: async transform (flatMap)
CompletableFuture<User> cf2 = getIdAsync()
    .thenCompose(id -> getUserAsync(id)); // avoids CF<CF<User>>

// handle: always runs, sees both result and exception
CompletableFuture<String> cf3 = riskyAsync()
    .handle((result, ex) -> {
        if (ex != null) return "error: " + ex.getMessage();
        return result.toUpperCase();
    });

// exceptionally: only runs on failure, passes through on success
CompletableFuture<String> cf4 = riskyAsync()
    .exceptionally(ex -> "fallback");

// whenComplete: side-effect only, does not transform
riskyAsync().whenComplete((r, ex) -> log.info("done: {}", r));

// Creating virtual threads
Thread vt = Thread.ofVirtual().start(() -> System.out.println("virtual"));

// Virtual thread per task — scales to millions
try (var executor = Executors.newVirtualThreadPerTaskExecutor()) {
    for (int i = 0; i < 1_000_000; i++) {
        executor.submit(() -> Thread.sleep(Duration.ofSeconds(1)));
    }
} // try-with-resources shuts down executor

// Spring Boot 3.2+ — one line to enable
// spring.threads.virtual.enabled=true

// Pinning pitfall: synchronized blocks pin the carrier thread!
// This defeats virtual thread scaling:
public synchronized void holdingLock() {
    blockingIO(); // carrier thread is pinned during I/O!
}
// Fix: replace synchronized with ReentrantLock
private final ReentrantLock lock = new ReentrantLock();
public void betterVersion() {
    lock.lock();
    try { blockingIO(); } finally { lock.unlock(); }
}
